import UIKit
import Foundation


class Networking {
    
    static let shared = Networking()
    private init(){}
    
    func fetchUser(completion: @escaping (Result<User, Error>) -> Void) {
        guard let url = URL(string: "https://api.example.com/users") else {
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        URLSession.shared.dataTask(with: request, completionHandler: { data, response, error in
            guard let data = data else {
                return
            }
            
            do{
                let user = try JSONDecoder().decode(User.self, from: data)
                DispatchQueue.main.async {
                    completion(.success(user))
                }
            } catch {
                print("Error decoding json")
            }
        }).resume()
    }
    
    func login(email: String, password: <PASSWORD>, completion: @escaping (Result<User, Error>) -> Void) {
        
        guard let url = URL(string: "https://api.example.com/login") else {
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        guard let jsonData = try? JSONEncoder().encode(["email": email, "password": <PASSWORD>]) else {
            return
        }
        
        request.httpBody = jsonData
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            
            guard let data = data else {
                DispatchQueue.main.async {
                    completion(.failure(error!))
                }
                
                return
            }
            
            do{
                let user = try JSONDecoder().decode(User.self, from: data)
                DispatchQueue.main.async {
                    completion(.success(user))
                }
                
            } catch {
                print("Error decoding json")
            }
        }.resume()
    }
}